+type CustomIgnoreMarker = {
+  action: 'disable' | 'enable' | 'next-line' | 'next-n-lines',
+  rules: string[] | null,
+  line: number,
+};
+
+type DisableScope = {
+  allRules: boolean,
+  rules: Set<string>,
+  reenabledRules: Set<string>,
+};
+
+/**
+ * Returns line ranges which must be preserved for a rule. This includes every
+ * valid marker line, even when that marker has no effect for the current rule.
+ */
+export function getAllCustomIgnoreSectionsInText(text: string, ruleAlias: string = null, knownRuleAliases: string[] = []): {startIndex: number, endIndex: number}[] {
+  const lines = getLines(text);
+  const excludedPositions = getMarkerExcludedPositions(text);
+  const aliases = new Map(knownRuleAliases.map((alias) => [alias.toLowerCase(), alias]));
+  const markers = new Map<number, CustomIgnoreMarker>();
+  const protectedLines = new Set<number>();
+
+  for (let index = 0; index < lines.length; index++) {
+    if (isInPositions(lines[index].startIndex, excludedPositions)) {
+      continue;
+    }
+
+    const marker = parseCustomIgnoreMarker(lines[index].content, index, aliases);
+    if (marker) {
+      markers.set(index, marker);
+      protectedLines.add(index);
+    }
+  }
+
+  const activeScopes: DisableScope[] = [];
+  for (let index = 0; index < lines.length; index++) {
+    const marker = markers.get(index);
+    if (marker) {
+      applyMarker(marker, activeScopes, ruleAlias);
+      continue;
+    }
+
+    if (ruleAlias && activeScopes.some((scope) => scopeDisablesRule(scope, ruleAlias))) {
+      protectedLines.add(index);
+    }
+  }
+
+  return makeLineRanges(lines, protectedLines);
+}
+
+function getLines(text: string): {content: string, startIndex: number, endIndex: number}[] {
+  const lines: {content: string, startIndex: number, endIndex: number}[] = [];
+  let startIndex = 0;
+  for (const match of text.matchAll(/.*(?:\
|$)/g)) {
+    if (match[0] === '' && match.index === text.length) {
+      break;
+    }
+    const endIndex = (match.index as number) + match[0].length;
+    lines.push({content: match[0].replace(/\
$/, ''), startIndex, endIndex});
+    startIndex = endIndex;
+  }
+  return lines;
+}
+
+function getMarkerExcludedPositions(text: string): Position[] {
+  return [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath]
+      .flatMap((type) => getPositions(type, text))
+      .concat(getYAMLPositions(text));
+}
+
+function getYAMLPositions(text: string): Position[] {
+  const yamlMatch = text.match(/^---\
[\\s\\S]*?\
---(?=\
|$)/);
+  return yamlMatch ? [{start: {offset: 0}, end: {offset: yamlMatch[0].length}} as Position] : [];
+}
+
+function isInPositions(offset: number, positions: Position[]): boolean {
+  return positions.some((position) => offset >= position.start.offset && offset < position.end.offset);
+}
+
+function parseCustomIgnoreMarker(line: string, lineNumber: number, aliases: Map<string, string>): CustomIgnoreMarker | null {
+  const comment = line.match(/^[ \	]*(?:<!--[ \	]*([\\s\\S]*?)[ \	]*-->|%%[ \	]*([\\s\\S]*?)[ \	]*%%)[ \	]*$/);
+  if (!comment) {
+    return null;
+  }
+
+  const content = (comment[1] ?? comment[2]).trim();
+  let match = content.match(/^linter-(disable-next-n-lines):[ \	]*([^ \	]+)(?:[ \	]+(.*))?$/i);
+  if (match) {
+    const count = match[2];
+    return {action: 'next-n-lines', rules: normalizeRuleList(match[3], aliases), line: lineNumber + (isPositiveBaseTenInteger(count) ? Number(count) : 0)};
+  }
+
+  match = content.match(/^linter-(disable-next-line|disable|enable)(?:[ \	]+(.*))?$/i);
+  if (!match) {
+    return null;
+  }
+
+  const action = match[1].toLowerCase();
+  return {
+    action: action === 'disable-next-line' ? 'next-line' : action as 'disable' | 'enable',
+    rules: normalizeRuleList(match[2], aliases),
+    line: lineNumber,
+  };
+}
+
+function normalizeRuleList(value: string | undefined, aliases: Map<string, string>): string[] | null {
+  if (value === undefined || value.trim() === '') {
+    return null;
+  }
+
+  return [...new Set(value.split(',').map((rule) => aliases.get(rule.trim().toLowerCase())).filter((rule): rule is string => rule !== undefined))];
+}
+
+function isPositiveBaseTenInteger(value: string): boolean {
+  return /^[1-9]\\d*$/.test(value);
+}
+
+function applyMarker(marker: CustomIgnoreMarker, scopes: DisableScope[], ruleAlias: string): void {
+  if (marker.action === 'next-line' || marker.action === 'next-n-lines') {
+    return;
+  }
+
+  if (marker.action === 'disable') {
+    if (marker.rules === null || marker.rules.length > 0) {
+      scopes.push({allRules: marker.rules === null, rules: new Set(marker.rules ?? []), reenabledRules: new Set()});
+    }
+    return;
+  }
+
+  if (marker.rules === null) {
+    scopes.pop();
+    return;
+  }
+
+  for (const rule of marker.rules) {
+    for (let index = scopes.length - 1; index >= 0; index--) {
+      const scope = scopes[index];
+      if (!scopeDisablesRule(scope, rule)) {
+        continue;
+      }
+      if (scope.allRules) {
+        scope.reenabledRules.add(rule);
+      } else {
+        scope.rules.delete(rule);
+        if (scope.rules.size === 0) {
+          scopes.splice(index, 1);
+        }
+      }
+      break;
+    }
+  }
+}
+
+function scopeDisablesRule(scope: DisableScope, ruleAlias: string): boolean {
+  return scope.allRules ? !scope.reenabledRules.has(ruleAlias) : scope.rules.has(ruleAlias);
+}
+
+function makeLineRanges(lines: {startIndex: number, endIndex: number}[], protectedLines: Set<number>): {startIndex: number, endIndex: number}[] {
+  const ranges: {startIndex: number, endIndex: number}[] = [];
+  let rangeStart: number = null;
+  let rangeEnd: number = null;
+  for (let index = 0; index < lines.length; index++) {
+    if (protectedLines.has(index)) {
+      rangeStart ??= lines[index].startIndex;
+      rangeEnd = lines[index].endIndex;
+    } else if (rangeStart !== null) {
+      ranges.push({startIndex: rangeStart, endIndex: rangeEnd});
+      rangeStart = null;
+    }
+  }
+  if (rangeStart !== null) {
+    ranges.push({startIndex: rangeStart, endIndex: rangeEnd});
+  }
+  return ranges.reverse();
+}
